6: import { IPosition, Position } from './position.js';
7: 
8: /**
9:  * A range in the editor. This interface is suitable for serialization.
10:  */
11: export interface IRange {
12: 	/**
13: 	 * Line number on which the range starts (starts at 1).
14: 	 */
15: 	readonly startLineNumber: number;
16: 	/**
17: 	 * Column on which the range starts in line `startLineNumber` (starts at 1).
18: 	 */
19: 	readonly startColumn: number;
20: 	/**
21: 	 * Line number on which the range ends.
22: 	 */
23: 	readonly endLineNumber: number;
24: 	/**
25: 	 * Column on which the range ends in line `endLineNumber`.
26: 	 */
27: 	readonly endColumn: number;
28: }
29: 
30: /**
31:  * A range in the editor. (startLineNumber,startColumn) is <= (endLineNumber,endColumn)
32:  */
33: export class Range {
34: 
35: 	/**
36: 	 * Line number on which the range starts (starts at 1).
37: 	 */
38: 	public readonly startLineNumber: number;
39: 	/**
40: 	 * Column on which the range starts in line `startLineNumber` (starts at 1).
41: 	 */
42: 	public readonly startColumn: number;
43: 	/**
44: 	 * Line number on which the range ends.
45: 	 */
46: 	public readonly endLineNumber: number;
47: 	/**
48: 	 * Column on which the range ends in line `endLineNumber`.
49: 	 */
50: 	public readonly endColumn: number;
51: 
52: 	constructor(startLineNumber: number, startColumn: number, endLineNumber: number, endColumn: number) {
53: 		if ((startLineNumber > endLineNumber) || (startLineNumber === endLineNumber && startColumn > endColumn)) {
54: 			this.startLineNumber = endLineNumber;
55: 			this.startColumn = endColumn;
56: 			this.endLineNumber = startLineNumber;
57: 			this.endColumn = startColumn;
58: 		} else {
59: 			this.startLineNumber = startLineNumber;
60: 			this.startColumn = startColumn;
61: 			this.endLineNumber = endLineNumber;
62: 			this.endColumn = endColumn;
63: 		}
64: 	}
65: 
66: 	/**
67: 	 * Test if this range is empty.
68: 	 */
69: 	public isEmpty(): boolean {
70: 		return Range.isEmpty(this);
71: 	}
72: 
73: 	/**
74: 	 * Test if `range` is empty.
75: 	 */
76: 	public static isEmpty(range: IRange): boolean {
77: 		return (range.startLineNumber === range.endLineNumber && range.startColumn === range.endColumn);
78: 	}
79: 
80: 	/**
81: 	 * Test if position is in this range. If the position is at the edges, will return true.
82: 	 */
83: 	public containsPosition(position: IPosition): boolean {
84: 		return Range.containsPosition(this, position);
85: 	}
86: 
87: 	/**
88: 	 * Test if `position` is in `range`. If the position is at the edges, will return true.
89: 	 */
90: 	public static containsPosition(range: IRange, position: IPosition): boolean {
91: 		if (position.lineNumber < range.startLineNumber || position.lineNumber > range.endLineNumber) {
92: 			return false;
93: 		}
94: 		if (position.lineNumber === range.startLineNumber && position.column < range.startColumn) {
95: 			return false;
96: 		}
97: 		if (position.lineNumber === range.endLineNumber && position.column > range.endColumn) {
98: 			return false;
99: 		}
100: 		return true;
101: 	}
102: 
103: 	/**
104: 	 * Test if `position` is in `range`. If the position is at the edges, will return false.
105: 	 * @internal
106: 	 */
107: 	public static strictContainsPosition(range: IRange, position: IPosition): boolean {
108: 		if (position.lineNumber < range.startLineNumber || position.lineNumber > range.endLineNumber) {
109: 			return false;
110: 		}
111: 		if (position.lineNumber === range.startLineNumber && position.column <= range.startColumn) {
112: 			return false;
113: 		}
114: 		if (position.lineNumber === range.endLineNumber && position.column >= range.endColumn) {
115: 			return false;
116: 		}
117: 		return true;
118: 	}
119: 
120: 	/**
121: 	 * Test if range is in this range. If the range is equal to this range, will return true.
122: 	 */
123: 	public containsRange(range: IRange): boolean {
124: 		return Range.containsRange(this, range);
125: 	}
126: 
127: 	/**
128: 	 * Test if `otherRange` is in `range`. If the ranges are equal, will return true.
129: 	 */
130: 	public static containsRange(range: IRange, otherRange: IRange): boolean {
131: 		if (otherRange.startLineNumber < range.startLineNumber || otherRange.endLineNumber < range.startLineNumber) {
132: 			return false;
133: 		}
134: 		if (otherRange.startLineNumber > range.endLineNumber || otherRange.endLineNumber > range.endLineNumber) {
135: 			return false;
136: 		}
137: 		if (otherRange.startLineNumber === range.startLineNumber && otherRange.startColumn < range.startColumn) {
138: 			return false;
139: 		}
140: 		if (otherRange.endLineNumber === range.endLineNumber && otherRange.endColumn > range.endColumn) {
141: 			return false;
142: 		}
143: 		return true;
144: 	}
145: 
146: 	/**
147: 	 * Test if `range` is strictly in this range. `range` must start after and end before this range for the result to be true.
148: 	 */
149: 	public strictContainsRange(range: IRange): boolean {
150: 		return Range.strictContainsRange(this, range);
151: 	}
152: 
153: 	/**
154: 	 * Test if `otherRange` is strictly in `range` (must start after, and end before). If the ranges are equal, will return false.
155: 	 */
156: 	public static strictContainsRange(range: IRange, otherRange: IRange): boolean {
157: 		if (otherRange.startLineNumber < range.startLineNumber || otherRange.endLineNumber < range.startLineNumber) {
158: 			return false;
159: 		}
160: 		if (otherRange.startLineNumber > range.endLineNumber || otherRange.endLineNumber > range.endLineNumber) {
161: 			return false;
162: 		}
163: 		if (otherRange.startLineNumber === range.startLineNumber && otherRange.startColumn <= range.startColumn) {
164: 			return false;
165: 		}
166: 		if (otherRange.endLineNumber === range.endLineNumber && otherRange.endColumn >= range.endColumn) {
167: 			return false;
168: 		}
169: 		return true;
170: 	}
171: 
172: 	/**
173: 	 * A reunion of the two ranges.
174: 	 * The smallest position will be used as the start point, and the largest one as the end point.
175: 	 */
176: 	public plusRange(range: IRange): Range {
177: 		return Range.plusRange(this, range);
178: 	}
179: 
180: 	/**
181: 	 * A reunion of the two ranges.
182: 	 * The smallest position will be used as the start point, and the largest one as the end point.
183: 	 */
184: 	public static plusRange(a: IRange, b: IRange): Range {
185: 		let startLineNumber: number;
186: 		let startColumn: number;
187: 		let endLineNumber: number;
188: 		let endColumn: number;
189: 
190: 		if (b.startLineNumber < a.startLineNumber) {
191: 			startLineNumber = b.startLineNumber;
192: 			startColumn = b.startColumn;
193: 		} else if (b.startLineNumber === a.startLineNumber) {
194: 			startLineNumber = b.startLineNumber;
195: 			startColumn = Math.min(b.startColumn, a.startColumn);
196: 		} else {
197: 			startLineNumber = a.startLineNumber;
198: 			startColumn = a.startColumn;
199: 		}
200: 
201: 		if (b.endLineNumber > a.endLineNumber) {
202: 			endLineNumber = b.endLineNumber;
203: 			endColumn = b.endColumn;
204: 		} else if (b.endLineNumber === a.endLineNumber) {
205: 			endLineNumber = b.endLineNumber;
206: 			endColumn = Math.max(b.endColumn, a.endColumn);
207: 		} else {
208: 			endLineNumber = a.endLineNumber;
209: 			endColumn = a.endColumn;
210: 		}
211: 
212: 		return new Range(startLineNumber, startColumn, endLineNumber, endColumn);
213: 	}
214: 
215: 	/**
216: 	 * A intersection of the two ranges.
217: 	 */
218: 	public intersectRanges(range: IRange): Range | null {
219: 		return Range.intersectRanges(this, range);
220: 	}
221: 
222: 	/**
223: 	 * A intersection of the two ranges.
224: 	 */
225: 	public static intersectRanges(a: IRange, b: IRange): Range | null {
226: 		let resultStartLineNumber = a.startLineNumber;
227: 		let resultStartColumn = a.startColumn;
228: 		let resultEndLineNumber = a.endLineNumber;
229: 		let resultEndColumn = a.endColumn;
230: 		const otherStartLineNumber = b.startLineNumber;
231: 		const otherStartColumn = b.startColumn;
232: 		const otherEndLineNumber = b.endLineNumber;
233: 		const otherEndColumn = b.endColumn;
234: 
235: 		if (resultStartLineNumber < otherStartLineNumber) {
236: 			resultStartLineNumber = otherStartLineNumber;
237: 			resultStartColumn = otherStartColumn;
238: 		} else if (resultStartLineNumber === otherStartLineNumber) {
239: 			resultStartColumn = Math.max(resultStartColumn, otherStartColumn);
240: 		}
241: 
242: 		if (resultEndLineNumber > otherEndLineNumber) {
243: 			resultEndLineNumber = otherEndLineNumber;
244: 			resultEndColumn = otherEndColumn;
245: 		} else if (resultEndLineNumber === otherEndLineNumber) {
246: 			resultEndColumn = Math.min(resultEndColumn, otherEndColumn);
247: 		}
248: 
249: 		// Check if selection is now empty
250: 		if (resultStartLineNumber > resultEndLineNumber) {
251: 			return null;
252: 		}
253: 		if (resultStartLineNumber === resultEndLineNumber && resultStartColumn > resultEndColumn) {
254: 			return null;
255: 		}
256: 		return new Range(resultStartLineNumber, resultStartColumn, resultEndLineNumber, resultEndColumn);
257: 	}
258: 
259: 	/**
260: 	 * Test if this range equals other.
261: 	 */
262: 	public equalsRange(other: IRange | null | undefined): boolean {
263: 		return Range.equalsRange(this, other);
264: 	}
265: 
266: 	/**
267: 	 * Test if range `a` equals `b`.
268: 	 */
269: 	public static equalsRange(a: IRange | null | undefined, b: IRange | null | undefined): boolean {
270: 		if (!a && !b) {
271: 			return true;
272: 		}
273: 		return (
274: 			!!a &&
275: 			!!b &&
276: 			a.startLineNumber === b.startLineNumber &&
277: 			a.startColumn === b.startColumn &&
278: 			a.endLineNumber === b.endLineNumber &&
279: 			a.endColumn === b.endColumn
280: 		);
281: 	}
282: 
283: 	/**
284: 	 * Return the end position (which will be after or equal to the start position)
285: 	 */
286: 	public getEndPosition(): Position {
287: 		return Range.getEndPosition(this);
288: 	}
289: 
290: 	/**
291: 	 * Return the end position (which will be after or equal to the start position)
292: 	 */
293: 	public static getEndPosition(range: IRange): Position {
294: 		return new Position(range.endLineNumber, range.endColumn);
295: 	}
296: 
297: 	/**
298: 	 * Return the start position (which will be before or equal to the end position)
299: 	 */
300: 	public getStartPosition(): Position {
301: 		return Range.getStartPosition(this);
302: 	}
303: 
304: 	/**
305: 	 * Return the start position (which will be before or equal to the end position)
306: 	 */
307: 	public static getStartPosition(range: IRange): Position {
308: 		return new Position(range.startLineNumber, range.startColumn);
309: 	}
310: 
311: 	/**
312: 	 * Transform to a user presentable string representation.
313: 	 */
314: 	public toString(): string {
315: 		return '[' + this.startLineNumber + ',' + this.startColumn + ' -> ' + this.endLineNumber + ',' + this.endColumn + ']';
316: 	}
317: 
318: 	/**
319: 	 * Create a new range using this range's start position, and using endLineNumber and endColumn as the end position.
320: 	 */
321: 	public setEndPosition(endLineNumber: number, endColumn: number): Range {
322: 		return new Range(this.startLineNumber, this.startColumn, endLineNumber, endColumn);
323: 	}
324: 
325: 	/**
326: 	 * Create a new range using this range's end position, and using startLineNumber and startColumn as the start position.
327: 	 */
328: 	public setStartPosition(startLineNumber: number, startColumn: number): Range {
329: 		return new Range(startLineNumber, startColumn, this.endLineNumber, this.endColumn);
330: 	}
331: 
332: 	/**
333: 	 * Create a new empty range using this range's start position.
334: 	 */
335: 	public collapseToStart(): Range {
336: 		return Range.collapseToStart(this);
337: 	}
338: 
339: 	/**
340: 	 * Create a new empty range using this range's start position.
341: 	 */
342: 	public static collapseToStart(range: IRange): Range {
343: 		return new Range(range.startLineNumber, range.startColumn, range.startLineNumber, range.startColumn);
344: 	}
345: 
346: 	/**
347: 	 * Create a new empty range using this range's end position.
348: 	 */
349: 	public collapseToEnd(): Range {
350: 		return Range.collapseToEnd(this);
351: 	}
352: 
353: 	/**
354: 	 * Create a new empty range using this range's end position.
355: 	 */
356: 	public static collapseToEnd(range: IRange): Range {
357: 		return new Range(range.endLineNumber, range.endColumn, range.endLineNumber, range.endColumn);
358: 	}
359: 
360: 	/**
361: 	 * Moves the range by the given amount of lines.
362: 	 */
363: 	public delta(lineCount: number): Range {
364: 		return new Range(this.startLineNumber + lineCount, this.startColumn, this.endLineNumber + lineCount, this.endColumn);
365: 	}
366: 
367: 	// ---
368: 
369: 	public static fromPositions(start: IPosition, end: IPosition = start): Range {
370: 		return new Range(start.lineNumber, start.column, end.lineNumber, end.column);
371: 	}
372: 
373: 	/**
374: 	 * Create a `Range` from an `IRange`.
375: 	 */
376: 	public static lift(range: undefined | null): null;
377: 	public static lift(range: IRange): Range;
378: 	public static lift(range: IRange | undefined | null): Range | null;
379: 	public static lift(range: IRange | undefined | null): Range | null {
380: 		if (!range) {
381: 			return null;
382: 		}
383: 		return new Range(range.startLineNumber, range.startColumn, range.endLineNumber, range.endColumn);
384: 	}
385: 
386: 	/**
387: 	 * Test if `obj` is an `IRange`.
388: 	 */
389: 	public static isIRange(obj: any): obj is IRange {
390: 		return (
391: 			obj
392: 			&& (typeof obj.startLineNumber === 'number')
393: 			&& (typeof obj.startColumn === 'number')
394: 			&& (typeof obj.endLineNumber === 'number')
395: 			&& (typeof obj.endColumn === 'number')
396: 		);
397: 	}
398: 
399: 	/**
400: 	 * Test if the two ranges are touching in any way.
401: 	 */
402: 	public static areIntersectingOrTouching(a: IRange, b: IRange): boolean {
403: 		// Check if `a` is before `b`
404: 		if (a.endLineNumber < b.startLineNumber || (a.endLineNumber === b.startLineNumber && a.endColumn < b.startColumn)) {
405: 			return false;
406: 		}
407: 
408: 		// Check if `b` is before `a`
409: 		if (b.endLineNumber < a.startLineNumber || (b.endLineNumber === a.startLineNumber && b.endColumn < a.startColumn)) {
410: 			return false;
411: 		}
412: 
413: 		// These ranges must intersect
414: 		return true;
415: 	}
416: 
417: 	/**
418: 	 * Test if the two ranges are intersecting. If the ranges are touching it returns true.
419: 	 */
420: 	public static areIntersecting(a: IRange, b: IRange): boolean {
421: 		// Check if `a` is before `b`
422: 		if (a.endLineNumber < b.startLineNumber || (a.endLineNumber === b.startLineNumber && a.endColumn <= b.startColumn)) {
423: 			return false;
424: 		}
425: 
426: 		// Check if `b` is before `a`
427: 		if (b.endLineNumber < a.startLineNumber || (b.endLineNumber === a.startLineNumber && b.endColumn <= a.startColumn)) {
428: 			return false;
429: 		}
430: 
431: 		// These ranges must intersect
432: 		return true;
433: 	}
434: 
435: 	/**
436: 	 * A function that compares ranges, useful for sorting ranges
437: 	 * It will first compare ranges on the startPosition and then on the endPosition
438: 	 */
439: 	public static compareRangesUsingStarts(a: IRange | null | undefined, b: IRange | null | undefined): number {
440: 		if (a && b) {
441: 			const aStartLineNumber = a.startLineNumber | 0;
442: 			const bStartLineNumber = b.startLineNumber | 0;
443: 
444: 			if (aStartLineNumber === bStartLineNumber) {
445: 				const aStartColumn = a.startColumn | 0;
446: 				const bStartColumn = b.startColumn | 0;
447: 
448: 				if (aStartColumn === bStartColumn) {
449: 					const aEndLineNumber = a.endLineNumber | 0;
450: 					const bEndLineNumber = b.endLineNumber | 0;
451: 
452: 					if (aEndLineNumber === bEndLineNumber) {
453: 						const aEndColumn = a.endColumn | 0;
454: 						const bEndColumn = b.endColumn | 0;
455: 						return aEndColumn - bEndColumn;
456: 					}
457: 					return aEndLineNumber - bEndLineNumber;
458: 				}
459: 				return aStartColumn - bStartColumn;
460: 			}
461: 			return aStartLineNumber - bStartLineNumber;
462: 		}
463: 		const aExists = (a ? 1 : 0);
464: 		const bExists = (b ? 1 : 0);
465: 		return aExists - bExists;
466: 	}
467: 
468: 	/**
469: 	 * A function that compares ranges, useful for sorting ranges
470: 	 * It will first compare ranges on the endPosition and then on the startPosition
471: 	 */
472: 	public static compareRangesUsingEnds(a: IRange, b: IRange): number {
473: 		if (a.endLineNumber === b.endLineNumber) {
474: 			if (a.endColumn === b.endColumn) {
475: 				if (a.startLineNumber === b.startLineNumber) {
476: 					return a.startColumn - b.startColumn;
477: 				}
478: 				return a.startLineNumber - b.startLineNumber;
479: 			}
480: 			return a.endColumn - b.endColumn;
481: 		}
482: 		return a.endLineNumber - b.endLineNumber;
483: 	}
484: 
485: 	/**
486: 	 * Test if the range spans multiple lines.
487: 	 */
488: 	public static spansMultipleLines(range: IRange): boolean {
489: 		return range.endLineNumber > range.startLineNumber;
490: 	}
491: 
492: 	public toJSON(): IRange {
493: 		return this;
494: 	}
495: }
