16: export class SearchParams {
17: 	public readonly searchString: string;
18: 	public readonly isRegex: boolean;
19: 	public readonly matchCase: boolean;
20: 	public readonly wordSeparators: string | null;
21: 
22: 	constructor(searchString: string, isRegex: boolean, matchCase: boolean, wordSeparators: string | null) {
23: 		this.searchString = searchString;
24: 		this.isRegex = isRegex;
25: 		this.matchCase = matchCase;
26: 		this.wordSeparators = wordSeparators;
27: 	}
28: 
29: 	public parseSearchRequest(): SearchData | null {
30: 		if (this.searchString === '') {
31: 			return null;
32: 		}
33: 
34: 		// Try to create a RegExp out of the params
35: 		let multiline: boolean;
36: 		if (this.isRegex) {
37: 			multiline = isMultilineRegexSource(this.searchString);
38: 		} else {
39: 			multiline = (this.searchString.indexOf('\n') >= 0);
40: 		}
41: 
42: 		let regex: RegExp | null = null;
43: 		try {
44: 			regex = strings.createRegExp(this.searchString, this.isRegex, {
45: 				matchCase: this.matchCase,
46: 				wholeWord: false,
47: 				multiline: multiline,
48: 				global: true,
49: 				unicode: true
50: 			});
51: 		} catch (err) {
52: 			return null;
53: 		}
54: 
55: 		if (!regex) {
56: 			return null;
57: 		}
58: 
59: 		let canUseSimpleSearch = (!this.isRegex && !multiline);
60: 		if (canUseSimpleSearch && this.searchString.toLowerCase() !== this.searchString.toUpperCase()) {
61: 			// casing might make a difference
62: 			canUseSimpleSearch = this.matchCase;
63: 		}
64: 
65: 		return new SearchData(regex, this.wordSeparators ? getMapForWordSeparators(this.wordSeparators, []) : null, canUseSimpleSearch ? this.searchString : null);
66: 	}
67: }
