161: export class TextModelSearch {
162: 
163: 	public static findMatches(model: TextModel, searchParams: SearchParams, searchRange: Range, captureMatches: boolean, limitResultCount: number): FindMatch[] {
164: 		const searchData = searchParams.parseSearchRequest();
165: 		if (!searchData) {
166: 			return [];
167: 		}
168: 
169: 		if (searchData.regex.multiline) {
170: 			return this._doFindMatchesMultiline(model, searchRange, new Searcher(searchData.wordSeparators, searchData.regex), captureMatches, limitResultCount);
171: 		}
172: 		return this._doFindMatchesLineByLine(model, searchRange, searchData, captureMatches, limitResultCount);
173: 	}
174: 
175: 	/**
176: 	 * Multiline search always executes on the lines concatenated with \n.
177: 	 * We must therefore compensate for the count of \n in case the model is CRLF
178: 	 */
179: 	private static _getMultilineMatchRange(model: TextModel, deltaOffset: number, text: string, lfCounter: LineFeedCounter | null, matchIndex: number, match0: string): Range {
180: 		let startOffset: number;
181: 		let lineFeedCountBeforeMatch = 0;
182: 		if (lfCounter) {
183: 			lineFeedCountBeforeMatch = lfCounter.findLineFeedCountBeforeOffset(matchIndex);
184: 			startOffset = deltaOffset + matchIndex + lineFeedCountBeforeMatch /* add as many \r as there were \n */;
185: 		} else {
186: 			startOffset = deltaOffset + matchIndex;
187: 		}
188: 
189: 		let endOffset: number;
190: 		if (lfCounter) {
191: 			const lineFeedCountBeforeEndOfMatch = lfCounter.findLineFeedCountBeforeOffset(matchIndex + match0.length);
192: 			const lineFeedCountInMatch = lineFeedCountBeforeEndOfMatch - lineFeedCountBeforeMatch;
193: 			endOffset = startOffset + match0.length + lineFeedCountInMatch /* add as many \r as there were \n */;
194: 		} else {
195: 			endOffset = startOffset + match0.length;
196: 		}
197: 
198: 		const startPosition = model.getPositionAt(startOffset);
199: 		const endPosition = model.getPositionAt(endOffset);
200: 		return new Range(startPosition.lineNumber, startPosition.column, endPosition.lineNumber, endPosition.column);
201: 	}
202: 
203: 	private static _doFindMatchesMultiline(model: TextModel, searchRange: Range, searcher: Searcher, captureMatches: boolean, limitResultCount: number): FindMatch[] {
204: 		const deltaOffset = model.getOffsetAt(searchRange.getStartPosition());
205: 		// We always execute multiline search over the lines joined with \n
206: 		// This makes it that \n will match the EOL for both CRLF and LF models
207: 		// We compensate for offset errors in `_getMultilineMatchRange`
208: 		const text = model.getValueInRange(searchRange, EndOfLinePreference.LF);
209: 		const lfCounter = (model.getEOL() === '\r\n' ? new LineFeedCounter(text) : null);
210: 
211: 		const result: FindMatch[] = [];
212: 		let counter = 0;
213: 
214: 		let m: RegExpExecArray | null;
215: 		searcher.reset(0);
216: 		while ((m = searcher.next(text))) {
217: 			result[counter++] = createFindMatch(this._getMultilineMatchRange(model, deltaOffset, text, lfCounter, m.index, m[0]), m, captureMatches);
218: 			if (counter >= limitResultCount) {
219: 				return result;
220: 			}
221: 		}
222: 
223: 		return result;
224: 	}
225: 
226: 	private static _doFindMatchesLineByLine(model: TextModel, searchRange: Range, searchData: SearchData, captureMatches: boolean, limitResultCount: number): FindMatch[] {
227: 		const result: FindMatch[] = [];
228: 		let resultLen = 0;
229: 
230: 		// Early case for a search range that starts & stops on the same line number
231: 		if (searchRange.startLineNumber === searchRange.endLineNumber) {
232: 			const text = model.getLineContent(searchRange.startLineNumber).substring(searchRange.startColumn - 1, searchRange.endColumn - 1);
233: 			resultLen = this._findMatchesInLine(searchData, text, searchRange.startLineNumber, searchRange.startColumn - 1, resultLen, result, captureMatches, limitResultCount);
234: 			return result;
235: 		}
236: 
237: 		// Collect results from first line
238: 		const text = model.getLineContent(searchRange.startLineNumber).substring(searchRange.startColumn - 1);
239: 		resultLen = this._findMatchesInLine(searchData, text, searchRange.startLineNumber, searchRange.startColumn - 1, resultLen, result, captureMatches, limitResultCount);
240: 
241: 		// Collect results from middle lines
242: 		for (let lineNumber = searchRange.startLineNumber + 1; lineNumber < searchRange.endLineNumber && resultLen < limitResultCount; lineNumber++) {
243: 			resultLen = this._findMatchesInLine(searchData, model.getLineContent(lineNumber), lineNumber, 0, resultLen, result, captureMatches, limitResultCount);
244: 		}
245: 
246: 		// Collect results from last line
247: 		if (resultLen < limitResultCount) {
248: 			const text = model.getLineContent(searchRange.endLineNumber).substring(0, searchRange.endColumn - 1);
249: 			resultLen = this._findMatchesInLine(searchData, text, searchRange.endLineNumber, 0, resultLen, result, captureMatches, limitResultCount);
250: 		}
251: 
252: 		return result;
253: 	}
254: 
255: 	private static _findMatchesInLine(searchData: SearchData, text: string, lineNumber: number, deltaOffset: number, resultLen: number, result: FindMatch[], captureMatches: boolean, limitResultCount: number): number {
256: 		const wordSeparators = searchData.wordSeparators;
257: 		if (!captureMatches && searchData.simpleSearch) {
258: 			const searchString = searchData.simpleSearch;
259: 			const searchStringLen = searchString.length;
260: 			const textLength = text.length;
261: 
262: 			let lastMatchIndex = -searchStringLen;
263: 			while ((lastMatchIndex = text.indexOf(searchString, lastMatchIndex + searchStringLen)) !== -1) {
264: 				if (!wordSeparators || isValidMatch(wordSeparators, text, textLength, lastMatchIndex, searchStringLen)) {
265: 					result[resultLen++] = new FindMatch(new Range(lineNumber, lastMatchIndex + 1 + deltaOffset, lineNumber, lastMatchIndex + 1 + searchStringLen + deltaOffset), null);
266: 					if (resultLen >= limitResultCount) {
267: 						return resultLen;
268: 					}
269: 				}
270: 			}
271: 			return resultLen;
272: 		}
273: 
274: 		const searcher = new Searcher(searchData.wordSeparators, searchData.regex);
275: 		let m: RegExpExecArray | null;
276: 		// Reset regex to search from the beginning
277: 		searcher.reset(0);
278: 		do {
279: 			m = searcher.next(text);
280: 			if (m) {
281: 				result[resultLen++] = createFindMatch(new Range(lineNumber, m.index + 1 + deltaOffset, lineNumber, m.index + 1 + m[0].length + deltaOffset), m, captureMatches);
282: 				if (resultLen >= limitResultCount) {
283: 					return resultLen;
284: 				}
285: 			}
286: 		} while (m);
287: 		return resultLen;
288: 	}
289: 
290: 	public static findNextMatch(model: TextModel, searchParams: SearchParams, searchStart: Position, captureMatches: boolean): FindMatch | null {
291: 		const searchData = searchParams.parseSearchRequest();
292: 		if (!searchData) {
293: 			return null;
294: 		}
295: 
296: 		const searcher = new Searcher(searchData.wordSeparators, searchData.regex);
297: 
298: 		if (searchData.regex.multiline) {
299: 			return this._doFindNextMatchMultiline(model, searchStart, searcher, captureMatches);
300: 		}
301: 		return this._doFindNextMatchLineByLine(model, searchStart, searcher, captureMatches);
302: 	}
303: 
304: 	private static _doFindNextMatchMultiline(model: TextModel, searchStart: Position, searcher: Searcher, captureMatches: boolean): FindMatch | null {
305: 		const searchTextStart = new Position(searchStart.lineNumber, 1);
306: 		const deltaOffset = model.getOffsetAt(searchTextStart);
307: 		const lineCount = model.getLineCount();
308: 		// We always execute multiline search over the lines joined with \n
309: 		// This makes it that \n will match the EOL for both CRLF and LF models
310: 		// We compensate for offset errors in `_getMultilineMatchRange`
311: 		const text = model.getValueInRange(new Range(searchTextStart.lineNumber, searchTextStart.column, lineCount, model.getLineMaxColumn(lineCount)), EndOfLinePreference.LF);
312: 		const lfCounter = (model.getEOL() === '\r\n' ? new LineFeedCounter(text) : null);
313: 		searcher.reset(searchStart.column - 1);
314: 		const m = searcher.next(text);
315: 		if (m) {
316: 			return createFindMatch(
317: 				this._getMultilineMatchRange(model, deltaOffset, text, lfCounter, m.index, m[0]),
318: 				m,
319: 				captureMatches
320: 			);
321: 		}
322: 
323: 		if (searchStart.lineNumber !== 1 || searchStart.column !== 1) {
324: 			// Try again from the top
325: 			return this._doFindNextMatchMultiline(model, new Position(1, 1), searcher, captureMatches);
326: 		}
327: 
328: 		return null;
329: 	}
330: 
331: 	private static _doFindNextMatchLineByLine(model: TextModel, searchStart: Position, searcher: Searcher, captureMatches: boolean): FindMatch | null {
332: 		const lineCount = model.getLineCount();
333: 		const startLineNumber = searchStart.lineNumber;
334: 
335: 		// Look in first line
336: 		const text = model.getLineContent(startLineNumber);
337: 		const r = this._findFirstMatchInLine(searcher, text, startLineNumber, searchStart.column, captureMatches);
338: 		if (r) {
339: 			return r;
340: 		}
341: 
342: 		for (let i = 1; i <= lineCount; i++) {
343: 			const lineIndex = (startLineNumber + i - 1) % lineCount;
344: 			const text = model.getLineContent(lineIndex + 1);
345: 			const r = this._findFirstMatchInLine(searcher, text, lineIndex + 1, 1, captureMatches);
346: 			if (r) {
347: 				return r;
348: 			}
349: 		}
350: 
351: 		return null;
352: 	}
353: 
354: 	private static _findFirstMatchInLine(searcher: Searcher, text: string, lineNumber: number, fromColumn: number, captureMatches: boolean): FindMatch | null {
355: 		// Set regex to search from column
356: 		searcher.reset(fromColumn - 1);
357: 		const m: RegExpExecArray | null = searcher.next(text);
358: 		if (m) {
359: 			return createFindMatch(
360: 				new Range(lineNumber, m.index + 1, lineNumber, m.index + 1 + m[0].length),
361: 				m,
362: 				captureMatches
363: 			);
364: 		}
365: 		return null;
366: 	}
367: 
368: 	public static findPreviousMatch(model: TextModel, searchParams: SearchParams, searchStart: Position, captureMatches: boolean): FindMatch | null {
369: 		const searchData = searchParams.parseSearchRequest();
370: 		if (!searchData) {
371: 			return null;
372: 		}
373: 
374: 		const searcher = new Searcher(searchData.wordSeparators, searchData.regex);
375: 
376: 		if (searchData.regex.multiline) {
377: 			return this._doFindPreviousMatchMultiline(model, searchStart, searcher, captureMatches);
378: 		}
379: 		return this._doFindPreviousMatchLineByLine(model, searchStart, searcher, captureMatches);
380: 	}
381: 
382: 	private static _doFindPreviousMatchMultiline(model: TextModel, searchStart: Position, searcher: Searcher, captureMatches: boolean): FindMatch | null {
383: 		const matches = this._doFindMatchesMultiline(model, new Range(1, 1, searchStart.lineNumber, searchStart.column), searcher, captureMatches, 10 * LIMIT_FIND_COUNT);
384: 		if (matches.length > 0) {
385: 			return matches[matches.length - 1];
386: 		}
387: 
388: 		const lineCount = model.getLineCount();
389: 		if (searchStart.lineNumber !== lineCount || searchStart.column !== model.getLineMaxColumn(lineCount)) {
390: 			// Try again with all content
391: 			return this._doFindPreviousMatchMultiline(model, new Position(lineCount, model.getLineMaxColumn(lineCount)), searcher, captureMatches);
392: 		}
393: 
394: 		return null;
395: 	}
396: 
397: 	private static _doFindPreviousMatchLineByLine(model: TextModel, searchStart: Position, searcher: Searcher, captureMatches: boolean): FindMatch | null {
398: 		const lineCount = model.getLineCount();
399: 		const startLineNumber = searchStart.lineNumber;
400: 
401: 		// Look in first line
402: 		const text = model.getLineContent(startLineNumber).substring(0, searchStart.column - 1);
403: 		const r = this._findLastMatchInLine(searcher, text, startLineNumber, captureMatches);
404: 		if (r) {
405: 			return r;
406: 		}
407: 
408: 		for (let i = 1; i <= lineCount; i++) {
409: 			const lineIndex = (lineCount + startLineNumber - i - 1) % lineCount;
410: 			const text = model.getLineContent(lineIndex + 1);
411: 			const r = this._findLastMatchInLine(searcher, text, lineIndex + 1, captureMatches);
412: 			if (r) {
413: 				return r;
414: 			}
415: 		}
416: 
417: 		return null;
418: 	}
419: 
420: 	private static _findLastMatchInLine(searcher: Searcher, text: string, lineNumber: number, captureMatches: boolean): FindMatch | null {
421: 		let bestResult: FindMatch | null = null;
422: 		let m: RegExpExecArray | null;
423: 		searcher.reset(0);
424: 		while ((m = searcher.next(text))) {
425: 			bestResult = createFindMatch(new Range(lineNumber, m.index + 1, lineNumber, m.index + 1 + m[0].length), m, captureMatches);
426: 		}
427: 		return bestResult;
428: 	}
429: }
