114: 	allNoModel(): T[] {
115: 		return this._entries.map(entry => entry.provider);
116: 	}
117: 
118: 	ordered(model: ITextModel, recursive = false): T[] {
119: 		const result: T[] = [];
120: 		this._orderedForEach(model, recursive, entry => result.push(entry.provider));
121: 		return result;
122: 	}
123: 
124: 	orderedGroups(model: ITextModel): T[][] {
125: 		const result: T[][] = [];
126: 		let lastBucket: T[];
127: 		let lastBucketScore: number;
128: 
129: 		this._orderedForEach(model, false, entry => {
130: 			if (lastBucket && lastBucketScore === entry._score) {
131: 				lastBucket.push(entry.provider);
132: 			} else {
133: 				lastBucketScore = entry._score;
134: 				lastBucket = [entry.provider];
135: 				result.push(lastBucket);
136: 			}
137: 		});
138: 
139: 		return result;
140: 	}
141: 
142: 	private _orderedForEach(model: ITextModel, recursive: boolean, callback: (provider: Entry<T>) => any): void {
143: 
144: 		this._updateScores(model, recursive);
145: 
146: 		for (const entry of this._entries) {
147: 			if (entry._score > 0) {
148: 				callback(entry);
149: 			}
150: 		}
151: 	}
152: 
153: 	private _lastCandidate: MatchCandidate | undefined;
154: 
155: 	private _updateScores(model: ITextModel, recursive: boolean): void {
156: 
157: 		const notebookInfo = this._notebookInfoResolver?.(model.uri);
158: 
159: 		// use the uri (scheme, pattern) of the notebook info iff we have one
160: 		// otherwise it's the model's/document's uri
161: 		const candidate = notebookInfo
162: 			? new MatchCandidate(model.uri, model.getLanguageId(), notebookInfo.uri, notebookInfo.type, recursive)
163: 			: new MatchCandidate(model.uri, model.getLanguageId(), undefined, undefined, recursive);
164: 
165: 		if (this._lastCandidate?.equals(candidate)) {
166: 			// nothing has changed
167: 			return;
168: 		}
169: 
170: 		this._lastCandidate = candidate;
171: 
172: 		for (const entry of this._entries) {
173: 			entry._score = score(entry.selector, candidate.uri, candidate.languageId, shouldSynchronizeModel(model), candidate.notebookUri, candidate.notebookType);
174: 
175: 			if (isExclusive(entry.selector) && entry._score > 0) {
176: 				if (recursive) {
177: 					entry._score = 0;
178: 				} else {
179: 					// support for one exclusive selector that overwrites
180: 					// any other selector
181: 					for (const entry of this._entries) {
182: 						entry._score = 0;
183: 					}
184: 					entry._score = 1000;
185: 					break;
186: 				}
187: 			}
188: 		}
189: 
190: 		// needs sorting
191: 		this._entries.sort(LanguageFeatureRegistry._compareByScoreAndTime);
192: 	}
193: 
194: 	private static _compareByScoreAndTime(a: Entry<any>, b: Entry<any>): number {
195: 		if (a._score < b._score) {
196: 			return 1;
197: 		} else if (a._score > b._score) {
198: 			return -1;
199: 		}
200: 
201: 		// De-prioritize built-in providers
202: 		if (isBuiltinSelector(a.selector) && !isBuiltinSelector(b.selector)) {
203: 			return 1;
204: 		} else if (!isBuiltinSelector(a.selector) && isBuiltinSelector(b.selector)) {
205: 			return -1;
206: 		}
207: 
208: 		if (a._time < b._time) {
209: 			return 1;
210: 		} else if (a._time > b._time) {
211: 			return -1;
212: 		} else {
213: 			return 0;
214: 		}
215: 	}
216: }
217: 
218: function isBuiltinSelector(selector: LanguageSelector): boolean {
219: 	if (typeof selector === 'string') {
220: 		return false;
221: 	}
222: 
223: 	if (Array.isArray(selector)) {
224: 		return selector.some(isBuiltinSelector);
225: 	}
226: 
227: 	return Boolean((selector as LanguageFilter).isBuiltin);
228: }
