207: export function createRegExp(searchString: string, isRegex: boolean, options: RegExpOptions = {}): RegExp {
208: 	if (!searchString) {
209: 		throw new Error('Cannot create regex from empty string');
210: 	}
211: 	if (!isRegex) {
212: 		searchString = escapeRegExpCharacters(searchString);
213: 	}
214: 	if (options.wholeWord) {
215: 		if (!/\B/.test(searchString.charAt(0))) {
216: 			searchString = '\\b' + searchString;
217: 		}
218: 		if (!/\B/.test(searchString.charAt(searchString.length - 1))) {
219: 			searchString = searchString + '\\b';
220: 		}
221: 	}
222: 	let modifiers = '';
223: 	if (options.global) {
224: 		modifiers += 'g';
225: 	}
226: 	if (!options.matchCase) {
227: 		modifiers += 'i';
228: 	}
229: 	if (options.multiline) {
230: 		modifiers += 'm';
231: 	}
232: 	if (options.unicode) {
233: 		modifiers += 'u';
234: 	}
235: 
236: 	return new RegExp(searchString, modifiers);
237: }
