239: export function regExpLeadsToEndlessLoop(regexp: RegExp): boolean {
240: 	// Exit early if it's one of these special cases which are meant to match
241: 	// against an empty string
242: 	if (regexp.source === '^' || regexp.source === '^$' || regexp.source === '$' || regexp.source === '^\\s*$') {
243: 		return false;
244: 	}
245: 
246: 	// We check against an empty string. If the regular expression doesn't advance
247: 	// (e.g. ends in an endless loop) it will match an empty string.
248: 	const match = regexp.exec('');
249: 	return !!(match && regexp.lastIndex === 0);
